import{_ as s,C as n,o as t,c as i,an as r,b as d,w as a,a as c,E as l,ao as u}from"./chunks/framework.CTqRDTHW.js";const S=JSON.parse('{"title":"Feature: Nervous System","description":"","frontmatter":{},"headers":[],"relativePath":"015-nervous-system/spec.md","filePath":"015-nervous-system/spec.md","lastUpdated":1772822285000}'),h={name:"015-nervous-system/spec.md"};function p(m,e,g,f,b,v){const o=n("Mermaid");return t(),i("div",null,[e[1]||(e[1]=r('<h1 id="feature-nervous-system" tabindex="-1">Feature: Nervous System <a class="header-anchor" href="#feature-nervous-system" aria-label="Permalink to &quot;Feature: Nervous System&quot;">​</a></h1><blockquote><p><strong>Spec</strong>: 015-nervous-system <strong>Date</strong>: 2026-03-05 <strong>Status</strong>: Implemented (Phases 1–3 complete; Integration verification pending) <strong>HLD</strong>: <code>docs/ard/NERVOUS-SYSTEM-HLD.md</code><strong>ARD</strong>: <code>docs/ard/NERVOUS-SYSTEM.md</code></p></blockquote><h2 id="target-modules" tabindex="-1">Target Modules <a class="header-anchor" href="#target-modules" aria-label="Permalink to &quot;Target Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Path</th><th>Impact</th></tr></thead><tbody><tr><td>Reasoner</td><td><code>services/reasoner/</code></td><td>Core — all three phases</td></tr><tr><td>Streaming</td><td><code>services/streaming/</code></td><td>arc-stream (Dr. Strange / Pulsar) health + profile</td></tr><tr><td>Messaging</td><td><code>services/messaging/</code></td><td>arc-pulse (Flash / NATS) subject schema</td></tr><tr><td>Cache</td><td><code>services/cache/</code></td><td>arc-db-cache (Sonic / Redis) cache layer</td></tr><tr><td>Contracts</td><td><code>services/reasoner/contracts/asyncapi.yaml</code></td><td>Event contract definitions</td></tr></tbody></table><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The nervous system wires arc-pulse (Flash / NATS), arc-stream (Dr. Strange / Pulsar), and arc-db-cache (Sonic / Redis) into a streaming-first inference backbone for arc-brain (Sherlock / LangGraph). Every request and response flows through Pulsar for analytics, billing, and the accuracy loop. Phase 1 reduces TTFT from 3–5s to sub-200ms by streaming tokens over NATS. Phase 2 removes retrieval from the critical path via parallel execution and Redis caching. Phase 3 establishes Pulsar as the platform-wide event backbone — every request received and every inference completed is published, enabling the accuracy loop, billing (Alfred), voice (Scarlett), and enterprise consumers to subscribe without touching Sherlock.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2>',7)),(t(),d(u,null,{default:a(()=>[l(o,{id:"mermaid-92",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20subgraph%20P1%5B%22PHASE%201%20%E2%80%94%20Fast%20Nerves%22%5D%0A%20%20%20%20%20%20%20%20N%5B%22arc-pulse%20(Flash%20%2F%20NATS)%22%5D%0A%20%20%20%20%20%20%20%20S%5B%22arc-brain%20(Sherlock%20%2F%20LangGraph)%22%5D%0A%20%20%20%20%20%20%20%20L%5B%22LLM%20API%22%5D%0A%20%20%20%20%20%20%20%20N%20--%3E%20S%0A%20%20%20%20%20%20%20%20S%20--%3E%7C%22stream_graph()%22%7C%20L%0A%20%20%20%20%20%20%20%20L%20--%3E%7C%22token%20chunks%22%7C%20S%0A%20%20%20%20%20%20%20%20S%20--%3E%7C%22reasoner.stream.%7Bid%7D%22%7C%20N%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20P2%5B%22PHASE%202%20%E2%80%94%20Muscle%20Memory%22%5D%0A%20%20%20%20%20%20%20%20SO%5B%22arc-db-cache%20(Sonic%20%2F%20Redis)%22%5D%0A%20%20%20%20%20%20%20%20CB%5B%22arc-db-vector%20(Cerebro%20%2F%20Qdrant)%22%5D%0A%20%20%20%20%20%20%20%20S2%5B%22arc-brain%20(Sherlock%20%2F%20LangGraph)%22%5D%0A%20%20%20%20%20%20%20%20S2%20--%3E%7C%22cache%20check%22%7C%20SO%0A%20%20%20%20%20%20%20%20S2%20--%3E%7C%22parallel%20vector%20search%22%7C%20CB%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20P3%5B%22PHASE%203%20%E2%80%94%20Spinal%20Cord%22%5D%0A%20%20%20%20%20%20%20%20P%5B%22arc-stream%20(Dr.%20Strange%20%2F%20Pulsar)%22%5D%0A%20%20%20%20%20%20%20%20RC%5B%22arc-guard%20(RoboCop%20%2F%20Guardrails)%5Cnpre%20%2B%20post%20check%22%5D%0A%20%20%20%20%20%20%20%20GR%5B%22arc-critic%20(Gordon%20Ramsay%20%2F%20Critic)%22%5D%0A%20%20%20%20%20%20%20%20AL%5B%22arc-billing%20(Alfred%20%2F%20Billing)%22%5D%0A%20%20%20%20%20%20%20%20AN%5B%22Analytics%20%2F%20Enterprise%22%5D%0A%20%20%20%20%20%20%20%20RC%20--%3E%7C%22pass%22%7C%20P%0A%20%20%20%20%20%20%20%20P%20--%3E%20GR%0A%20%20%20%20%20%20%20%20P%20--%3E%20AL%0A%20%20%20%20%20%20%20%20P%20--%3E%20AN%0A%20%20%20%20end%0A%0A%20%20%20%20P1%20--%3E%20P3%0A%20%20%20%20P2%20--%3E%20P3%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=r('<h2 id="user-scenarios-testing" tabindex="-1">User Scenarios &amp; Testing <a class="header-anchor" href="#user-scenarios-testing" aria-label="Permalink to &quot;User Scenarios &amp; Testing&quot;">​</a></h2><h3 id="p1-—-must-have" tabindex="-1">P1 — Must Have <a class="header-anchor" href="#p1-—-must-have" aria-label="Permalink to &quot;P1 — Must Have&quot;">​</a></h3><p><strong>US-1</strong>: As a client application, I want to receive inference tokens as they are generated so that users see a response begin within 200ms of their request.</p><ul><li><strong>Given</strong>: A request is published to <code>arc.reasoner.request</code> on arc-pulse (Flash / NATS)</li><li><strong>When</strong>: Sherlock processes the request via <code>stream_graph()</code></li><li><strong>Then</strong>: Token chunks arrive on <code>arc.reasoner.stream.{request_id}</code> within 200ms of request receipt; a completion signal arrives on <code>arc.reasoner.result</code> when done</li><li><strong>Test</strong>: Measure <code>ttft_seconds</code> histogram in arc-friday (Friday / SigNoz) — P50 &lt; 200ms after Phase 1</li></ul><p><strong>US-2</strong>: As the platform, I want every inbound request published to Pulsar immediately on arrival so that analytics, billing, and audit have a complete record including failed and rejected requests.</p><ul><li><strong>Given</strong>: Any request arrives at Sherlock (via NATS, HTTP, or MCP)</li><li><strong>When</strong>: The request is received (before any processing)</li><li><strong>Then</strong>: <code>arc.reasoner.request.received</code> is published to arc-stream (Dr. Strange / Pulsar) with full request metadata</li><li><strong>Test</strong>: Kill Sherlock mid-request — Pulsar topic still contains the <code>request.received</code> event</li></ul><p><strong>US-3</strong>: As the billing system (Alfred), I want token usage published for every completed inference so that per-user, per-model cost tracking is accurate.</p><ul><li><strong>Given</strong>: An inference completes successfully</li><li><strong>When</strong>: <code>arc.reasoner.inference.completed</code> is published</li><li><strong>Then</strong>: The event payload includes <code>usage.{input_tokens, output_tokens, total_tokens}</code>, <code>model</code>, <code>user_id</code>, and <code>ttft_ms</code></li><li><strong>Test</strong>: Run 100 requests; verify Alfred&#39;s <code>arc.billing.usage</code> topic receives 100 events with non-zero token counts</li></ul><p><strong>US-4</strong>: As a guardrail system (RoboCop), I want to check requests before LLM invocation and outputs before completion signal delivery so that unsafe content is blocked on both the input and output path.</p><ul><li><strong>Given</strong>: A request arrives at Sherlock</li><li><strong>When</strong>: Pre-check runs on the input (~15ms)</li><li><strong>Then</strong>: Prompt injection and policy violations are rejected before LLM starts; <code>arc.reasoner.guard.rejected</code> is published and the client receives a 4xx</li><li><strong>And When</strong>: Post-check runs on the full output (~40ms)</li><li><strong>Then</strong>: Unsafe outputs are intercepted; <code>arc.reasoner.guard.intercepted</code> is published and client receives a safe fallback</li><li><strong>Test</strong>: Send a known injection payload — verify LLM is never called; verify <code>guard.rejected</code> event on Pulsar</li></ul><h3 id="p2-—-should-have" tabindex="-1">P2 — Should Have <a class="header-anchor" href="#p2-—-should-have" aria-label="Permalink to &quot;P2 — Should Have&quot;">​</a></h3><p><strong>US-5</strong>: As a developer, I want context retrieval to run in parallel with LLM startup so that retrieval latency (~150-300ms) is removed from the critical path.</p><ul><li><strong>Given</strong>: A request with no Sonic cache hit</li><li><strong>When</strong>: <code>stream_graph()</code> starts</li><li><strong>Then</strong>: Embedding and vector search run concurrently with LLM warm-up; retrieved context is injected via LangGraph state mid-stream</li><li><strong>Test</strong>: Trace shows embed + vector search overlapping with LLM first-token time in Friday</li></ul><p><strong>US-6</strong>: As a repeat user, I want my context retrieval to be served from Redis cache so that repeated questions get sub-10ms retrieval instead of 200-400ms.</p><ul><li><strong>Given</strong>: A user has sent at least one prior request</li><li><strong>When</strong>: A semantically similar follow-up request arrives</li><li><strong>Then</strong>: Sonic cache is hit; <code>context_chunks</code> are returned in &lt;10ms; no Cerebro/pgvector query is made</li><li><strong>Test</strong>: Send identical query twice; verify second request has no Cerebro query in traces</li></ul><h3 id="p3-—-nice-to-have" tabindex="-1">P3 — Nice to Have <a class="header-anchor" href="#p3-—-nice-to-have" aria-label="Permalink to &quot;P3 — Nice to Have&quot;">​</a></h3><p><strong>US-7</strong>: As an enterprise consumer, I want to subscribe to <code>arc.reasoner.inference.completed</code> on arc-stream (Dr. Strange / Pulsar) so that I can build compliance audits, analytics pipelines, and second-model checks without modifying Sherlock.</p><ul><li><strong>Given</strong>: Phase 3 is deployed and <code>SHERLOCK_PULSAR_ENABLED=true</code></li><li><strong>When</strong>: Any inference completes</li><li><strong>Then</strong>: Any number of independent Pulsar subscribers receive the event; Sherlock is unaffected by subscriber count or behavior</li><li><strong>Test</strong>: Add 5 test subscribers — verify all receive events; verify Sherlock TTFT is unchanged</li></ul><p><strong>US-8</strong>: As the platform, I want NATS requests to fall back to Pulsar durable queue under overload so that no requests are dropped when NATS reply times out.</p><ul><li><strong>Given</strong>: NATS reply timeout (500ms) is exceeded</li><li><strong>When</strong>: Sherlock detects the timeout</li><li><strong>Then</strong>: Request is queued to <code>arc.reasoner.requests.durable</code> on Pulsar; result is delivered to original caller via correlation ID when capacity is available; if processing fails after 3 retries (exponential backoff: 100ms → 1s → 10s), request is published to <code>arc.reasoner.requests.failed</code> DLQ</li><li><strong>Test</strong>: Simulate NATS overload; verify requests complete via Pulsar fallback with correlation ID intact; verify retry exhaustion routes to DLQ</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="functional" tabindex="-1">Functional <a class="header-anchor" href="#functional" aria-label="Permalink to &quot;Functional&quot;">​</a></h3><ul><li>[x] FR-1: <code>nats_handler.py</code> and <code>openai_nats_handler.py</code> use <code>stream_graph()</code> by default; <code>invoke_graph()</code> is opt-in only</li><li>[x] FR-2: Token chunks published to <code>arc.reasoner.stream.{request_id}</code> subject on arc-pulse (Flash / NATS)</li><li>[x] FR-3: Completion signal published to <code>arc.reasoner.result</code> on NATS when stream ends</li><li>[x] FR-4: <code>arc.reasoner.request.received</code> published to arc-stream (Dr. Strange / Pulsar) on every inbound request before any processing</li><li>[x] FR-5: <code>arc.reasoner.inference.completed</code> published with full token usage payload after every completed inference</li><li>[x] FR-6: <code>SentenceTransformer.encode()</code> runs in <code>ThreadPoolExecutor</code> (off async event loop)</li><li>[x] FR-7: arc-db-cache (Sonic / Redis) cache checked before Cerebro/pgvector on every retrieval; cache key: <code>arc:ctx:{user_id}:{sha256(embedding)}</code></li><li>[x] FR-8: Cache TTL default 300s; explicit invalidation on new conversation message</li><li>[x] FR-9: RoboCop pre-check runs sync before <code>stream_graph()</code> on all transports</li><li>[x] FR-10: RoboCop post-check runs sync on full output before completion signal is sent to client</li><li>[x] FR-11: <code>arc.reasoner.guard.rejected</code> and <code>arc.reasoner.guard.intercepted</code> published on guard failures</li><li>[x] FR-12: NATS → Pulsar fallback on 500ms reply timeout</li><li>[x] FR-13: All Pulsar topics defined in <code>contracts/asyncapi.yaml</code> with JSON schema</li><li>[x] FR-14: Durable queue retry policy — max 3 retries with exponential backoff (100ms → 1s → 10s); exhausted requests published to <code>arc.reasoner.requests.failed</code> DLQ</li></ul><h3 id="non-functional" tabindex="-1">Non-Functional <a class="header-anchor" href="#non-functional" aria-label="Permalink to &quot;Non-Functional&quot;">​</a></h3><ul><li>[ ] NFR-1: P50 TTFT &lt; 200ms after Phase 1 + 2 (measured from request receive to first token emitted) — requires live infra measurement</li><li>[ ] NFR-2: RoboCop pre-check adds &lt;20ms; post-check adds &lt;50ms — requires live measurement</li><li>[x] NFR-3: Pulsar publish of <code>request.received</code> adds &lt;5ms — fire-and-forget via <code>asyncio.create_task</code>, never blocks ack</li><li>[ ] NFR-4: Sonic cache hit latency &lt;10ms P99 — requires live Redis measurement</li><li>[x] NFR-5: <code>stream_graph()</code> must not block the async event loop — uses <code>run_in_executor</code> for CPU encode, <code>async for</code> for streaming</li><li>[ ] NFR-6: All new code passes <code>ruff</code> + <code>mypy</code> with zero errors — 5 pre-existing mypy errors in changed files (not introduced by this feature)</li><li>[x] NFR-7: Test coverage ≥ 80% on all modified files — 347 tests pass; all Phase 1–3 paths exercised</li></ul><h3 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Entity</th><th>Module</th><th>Description</th></tr></thead><tbody><tr><td><code>InferenceCompletedEvent</code></td><td><code>reasoner/models_v1.py</code></td><td>Pulsar payload for <code>arc.reasoner.inference.completed</code> — includes token usage, TTFT, guard status</td></tr><tr><td><code>RequestReceivedEvent</code></td><td><code>reasoner/models_v1.py</code></td><td>Pulsar payload for <code>arc.reasoner.request.received</code></td></tr><tr><td><code>TokenUsage</code></td><td><code>reasoner/models_v1.py</code></td><td><code>{input_tokens, output_tokens, total_tokens}</code> — read by Alfred for billing</td></tr><tr><td><code>StreamChunk</code></td><td><code>reasoner/streaming.py</code></td><td>NATS message payload for token chunks</td></tr><tr><td><code>ContextCacheKey</code></td><td><code>reasoner/memory.py</code></td><td><code>arc:ctx:{user_id}:{sha256(embedding)}</code> — Redis key schema</td></tr></tbody></table><h2 id="edge-cases" tabindex="-1">Edge Cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Expected Behavior</th></tr></thead><tbody><tr><td>LLM errors mid-stream (after tokens sent)</td><td>Publish <code>arc.reasoner.inference.failed</code> with partial token count; client receives error chunk on NATS stream</td></tr><tr><td>Pulsar unavailable at Phase 3</td><td>Log warning + continue; NATS path unaffected; <code>SHERLOCK_PULSAR_ENABLED</code> feature flag allows degradation</td></tr><tr><td>arc-db-cache (Sonic / Redis) unavailable</td><td>Fall through to Cerebro/pgvector on every request; log cache miss; do not fail the request</td></tr><tr><td>RoboCop service unavailable</td><td>Fail open (pass request through) with warning log; publish <code>arc.guard.service_unavailable</code> event</td></tr><tr><td>NATS reply timeout (500ms)</td><td>Queue to <code>arc.reasoner.requests.durable</code> on Pulsar; deliver result via correlation ID when capacity available</td></tr><tr><td>Durable queue retry exhaustion</td><td>After 3 retries (exponential backoff: 100ms → 1s → 10s), publish to <code>arc.reasoner.requests.failed</code> DLQ; return error to caller via correlation ID; log with full context</td></tr><tr><td>Embedding takes &gt;500ms</td><td>Proceed with empty context; inject when ready; log <code>slow_embed</code> metric</td></tr><tr><td>Concurrent requests from same user</td><td>Each request gets its own Sonic cache check; no cross-request cache poisoning</td></tr></tbody></table><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li>[ ] SC-1: P50 TTFT &lt; 200ms measured on <code>ttft_seconds</code> histogram in arc-friday (Friday / SigNoz)</li><li>[ ] SC-2: <code>arc.reasoner.request.received</code> published for 100% of inbound requests including rejected and failed ones</li><li>[ ] SC-3: <code>arc.reasoner.inference.completed</code> payload includes non-zero <code>usage.total_tokens</code> for every successful inference</li><li>[ ] SC-4: RoboCop pre-check correctly rejects a known prompt injection payload without calling the LLM</li><li>[ ] SC-5: Sonic cache hit on second identical query; no Cerebro call in trace</li><li>[ ] SC-6: 5 independent Pulsar subscribers on <code>inference.completed</code> — all receive events; Sherlock TTFT unchanged</li><li>[ ] SC-7: All tests pass: <code>pytest services/reasoner/tests/ -v</code></li></ul><h2 id="docs-links-update" tabindex="-1">Docs &amp; Links Update <a class="header-anchor" href="#docs-links-update" aria-label="Permalink to &quot;Docs &amp; Links Update&quot;">​</a></h2><ul><li>[ ] Update <code>docs/ard/NERVOUS-SYSTEM.md</code> — mark phases complete as implemented</li><li>[ ] Update <code>docs/ard/NERVOUS-SYSTEM-HLD.md</code> — reflect any implementation divergence</li><li>[ ] Update <code>services/reasoner/contracts/asyncapi.yaml</code> — full event contract</li><li>[ ] Update <code>CLAUDE.md</code> service reference if new Pulsar topics change platform behaviour</li></ul><h2 id="constitution-compliance" tabindex="-1">Constitution Compliance <a class="header-anchor" href="#constitution-compliance" aria-label="Permalink to &quot;Constitution Compliance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Principle</th><th>Applies</th><th>Compliant</th><th>Notes</th></tr></thead><tbody><tr><td>I. Zero-Dep CLI</td><td>[ ]</td><td>[ ]</td><td>No CLI changes — services only</td></tr><tr><td>II. Platform-in-a-Box</td><td>[x]</td><td>[x]</td><td>Phase 3 Pulsar fan-out enables full platform event backbone</td></tr><tr><td>III. Modular Services</td><td>[x]</td><td>[x]</td><td>All subscribers independent; Sherlock unchanged after Phase 3</td></tr><tr><td>IV. Two-Brain</td><td>[x]</td><td>[x]</td><td>Python (Sherlock) owns inference; Go unaffected</td></tr><tr><td>V. Polyglot Standards</td><td>[x]</td><td>[x]</td><td>ruff + mypy enforced; asyncapi.yaml for contracts</td></tr><tr><td>VI. Local-First</td><td>[x]</td><td>[x]</td><td>Pulsar degrades gracefully if unavailable; NATS path unaffected</td></tr><tr><td>VII. Observability</td><td>[x]</td><td>[x]</td><td><code>ttft_seconds</code> histogram; all events carry trace context</td></tr><tr><td>VIII. Security</td><td>[x]</td><td>[x]</td><td>RoboCop pre/post checks on all transports; no secrets in events</td></tr><tr><td>IX. Declarative</td><td>[x]</td><td>[x]</td><td>asyncapi.yaml defines all topics + schemas</td></tr><tr><td>X. Stateful Ops</td><td>[x]</td><td>[x]</td><td>Redis cache + Pulsar durable queue for fallback</td></tr><tr><td>XI. Resilience</td><td>[x]</td><td>[x]</td><td>NATS → Pulsar fallback; Sonic fail-open; RoboCop fail-open</td></tr><tr><td>XII. Interactive</td><td>[ ]</td><td>[ ]</td><td>No TUI changes</td></tr></tbody></table>',35))])}const k=s(h,[["render",p]]);export{S as __pageData,k as default};
